  1	import React, { FC, useEffect, useState } from 'react';
  2	
  3	import HyperConvergedModel from '@kubevirt-ui/kubevirt-api/console/models/HyperConvergedModel';
  4	import NewBadge from '@kubevirt-utils/components/badges/NewBadge/NewBadge';
  5	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
  6	import { HyperConverged } from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
  7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  8	import { isEmpty } from '@kubevirt-utils/utils/utils';
  9	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Alert,
 12	  AlertVariant,
 13	  PopoverPosition,
 14	  Split,
 15	  SplitItem,
 16	  Switch,
 17	} from '@patternfly/react-core';
 18	
 19	import './KernelSamepageMerging.scss';
 20	
 21	type KernelSamepageMergingProps = {
 22	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: Error];
 23	  newBadge?: boolean;
 24	};
 25	const KernelSamepageMerging: FC<KernelSamepageMergingProps> = ({
 26	  hyperConvergeConfiguration,
 27	  newBadge = false,
 28	}) => {
 29	  const { t } = useKubevirtTranslation();
 30	  const [hyperConverge, hyperLoaded] = hyperConvergeConfiguration;
 31	  const ksmConfiguration = hyperConverge?.spec?.ksmConfiguration;
 32	  const [isEnabled, setIsEnabled] = useState<boolean>();
 33	
 34	  useEffect(
 35	    () =>
 36	      hyperLoaded &&
 37	      setIsEnabled(
 38	        !!(
 39	          ksmConfiguration?.hasOwnProperty('nodeLabelSelector') &&
 40	          // Empty nodeLabelSelector will enable KSM on every node.
 41	          isEmpty(ksmConfiguration?.nodeLabelSelector)
 42	        ),
 43	      ),
 44	    [ksmConfiguration, hyperLoaded],
 45	  );
 46	
 47	  const [error, setError] = useState(null);
 48	
 49	  const onKSMchange = (value: boolean) => {
 50	    k8sPatch<HyperConverged>({
 51	      data: [
 52	        {
 53	          op: !ksmConfiguration ? 'add' : 'replace',
 54	          path: `/spec/ksmConfiguration`,
 55	          value: value ? { nodeLabelSelector: {} } : {},
 56	        },
 57	      ],
 58	      model: HyperConvergedModel,
 59	      resource: hyperConverge,
 60	    })
 61	      .then(() => setIsEnabled(value))
 62	      .catch((err) => setError(err.message));
 63	  };
 64	
 65	  return (
 66	    <>
 67	      <Split>
 68	        <SplitItem isFilled>
 69	          {t('Kernel Samepage Merging (KSM)')}{' '}
 70	          <HelpTextIcon
 71	            bodyContent={t(
 72	              'KSM is a memory-saving deduplication feature designed to fit more VirtualMachines into physical memory by sharing the data common between them. It is specifically effective for similar VirtualMachines. KSM should only be used with trusted workloads. Turning this feature on enables it for all nodes in the cluster.',
 73	            )}
 74	            className="KernelSamepageMerging__HelpTextIcon"
 75	            helpIconClassName="KernelSamepageMerging__HelpIcon"
 76	            position={PopoverPosition.bottom}
 77	          />
 78	          {newBadge && <NewBadge />}
 79	        </SplitItem>
 80	        {hyperLoaded && (
 81	          <SplitItem>
 82	            <Switch
 83	              id="kernel-samepage-merging"
 84	              isChecked={isEnabled}
 85	              onChange={(_, checked: boolean) => onKSMchange(checked)}
 86	            />
 87	          </SplitItem>
 88	        )}
 89	      </Split>
 90	      {error && (
 91	        <Alert
 92	          className="KernelSamepageMerging__Alert"
 93	          isInline
 94	          title={t('An error occurred')}
 95	          variant={AlertVariant.danger}
 96	        >
 97	          {error}
 98	        </Alert>
 99	      )}
100	    </>
101	  );
102	};
103	
104	export default KernelSamepageMerging;

